arguments.content:
/* ── History Screen ────────────────────────────────────── */

.hist-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
  position: relative;
}

/* ── Scrollable ──────────────────────────────────────── */
.hist-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 16px;
}
.hist-scroll::-webkit-scrollbar { display: none; }

/* ── Title ───────────────────────────────────────────── */
.hist-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 4px 0 12px;
}

/* ── Day/Week/Month Toggle ───────────────────────────── */
.hist-toggle {
  display: flex;
  background: #fff;
  border-radius: 12px;
  padding: 4px;
  gap: 4px;
  margin-bottom: 14px;
  box-shadow: 0 2px 8px rgba(37,99,235,0.07);
}

.hist-tab {
  flex: 1;
  border: none;
  background: transparent;
  border-radius: 9px;
  padding: 8px 0;
  font-size: 13px;
  font-weight: 600;
  color: #7a8cad;
  cursor: pointer;
  transition: all 0.2s;
}

.hist-tab-active {
  background: #2563eb;
  color: #fff;
  box-shadow: 0 2px 8px rgba(37,99,235,0.25);
}

/* ── Cards ───────────────────────────────────────────── */
.hist-card {
  background: #fff;
  border-radius: 18px;
  padding: 14px;
  margin-bottom: 12px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
}

.hist-card-title-row {
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 10px;
}

.hist-card-title {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
}

.hist-card-sub {
  font-size: 11px;
  font-weight: 400;
  color: #9aadc9;
}

/* ── Trend Chart ─────────────────────────────────────── */
.hist-chart-wrap {
  width: 100%;
  overflow: hidden;
}

/* ── Distribution Card ───────────────────────────────── */
.hist-distrib-card {
  display: flex;
  gap: 12px;
  align-items: flex-start;
}

.hist-distrib-left {
  flex: 1;
  min-width: 0;
}

/* Donut */
.hist-donut-wrap {
  display: flex;
  justify-content: center;
  margin: 8px 0 10px;
}

.hist-donut-svg {
  width: 100px;
  height: 100px;
}

/* Legend */
.hist-legend {
  display: flex;
  flex-direction: column;
  gap: 5px;
}

.hist-legend-item {
  display: flex;
  align-items: flex-start;
  gap: 7px;
}

.hist-legend-dot {
  width: 10px; height: 10px;
  border-radius: 50%;
  flex-shrink: 0;
  margin-top: 2px;
}

.hist-legend-label {
  font-size: 11px;
  color: #1a2b4b;
}

.hist-legend-label strong { font-weight: 700; }

.hist-legend-sub {
  font-size: 10px;
  color: #9aadc9;
}

/* Stats right */
.hist-distrib-right {
  width: 44%;
  flex-shrink: 0;
  display: flex;
  flex-direction: column;
  gap: 10px;
  padding-top: 24px;
}

.hist-stat-item {
  display: flex;
  align-items: flex-start;
  gap: 9px;
  background: #f8faff;
  border-radius: 12px;
  padding: 8px 9px;
}

.hist-stat-icon {
  width: 30px; height: 30px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 13px;
  flex-shrink: 0;
}

.hist-stat-label {
  font-size: 9.5px;
  color: #7a8cad;
  line-height: 1.3;
  margin-bottom: 2px;
}

.hist-stat-val {
  font-size: 16px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1;
}

.hist-stat-val-sm {
  font-size: 12px;
  line-height: 1.3;
}

.hist-stat-unit {
  font-size: 10px;
  font-weight: 500;
  color: #9aadc9;
}

/* ── Section Title ───────────────────────────────────── */
.hist-section-title {
  font-size: 15px;
  font-weight: 800;
  color: #1a2b4b;
  margin-bottom: 10px;
}

/* ── Recent Sessions ─────────────────────────────────── */
.hist-sessions-list {
  background: #fff;
  border-radius: 18px;
  overflow: hidden;
  margin-bottom: 12px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
}

.hist-session-row {
  display: flex;
  align-items: center;
  gap: 10px;
  padding: 12px 14px;
  text-decoration: none;
  border-bottom: 1px solid #f0f4fa;
  transition: background 0.15s;
}

.hist-session-row:last-child { border-bottom: none; }
.hist-session-row:hover { background: #f8faff; }

.hist-session-date {
  display: flex;
  align-items: center;
  gap: 8px;
  flex: 1;
}

.hist-session-day {
  font-size: 12px;
  font-weight: 700;
  color: #1a2b4b;
  line-height: 1.1;
}

.hist-session-time {
  font-size: 10.5px;
  color: #9aadc9;
}

.hist-session-stress {
  display: flex;
  align-items: center;
  gap: 6px;
  min-width: 70px;
}

.hist-stress-dot {
  width: 9px; height: 9px;
  border-radius: 50%;
  flex-shrink: 0;
}

.hist-stress-level {
  font-size: 11.5px;
  font-weight: 700;
  color: #1a2b4b;
  line-height: 1.1;
}

.hist-stress-label {
  font-size: 10px;
  color: #9aadc9;
}

.hist-session-dur {
  display: flex;
  align-items: center;
  gap: 4px;
  font-size: 11px;
  color: #5a6882;
  font-weight: 600;
  min-width: 45px;
}

.hist-session-arrow {
  color: #c5d3e8;
  font-size: 11px;
  flex-shrink: 0;
}

/* ── Migraine Risk Card ──────────────────────────────── */
.hist-migraine-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: linear-gradient(135deg, #e6fdf5 0%, #d1fae5 100%);
  border-radius: 18px;
  padding: 14px;
  margin-bottom: 14px;
  border: 1px solid #a7f3d0;
  box-shadow: 0 2px 10px rgba(16,185,129,0.09);
  text-decoration: none;
}

.hist-migraine-icon {
  width: 42px; height: 42px;
  border-radius: 50%;
  background: #d1fae5;
  border: 2px solid #6ee7b7;
  display: flex; align-items: center; justify-content: center;
  color: #059669;
  font-size: 18px;
  flex-shrink: 0;
}

.hist-migraine-info { flex: 1; min-width: 0; }

.hist-migraine-label {
  font-size: 11px;
  font-weight: 600;
  color: #047857;
}

.hist-migraine-status {
  font-size: 16px;
  font-weight: 800;
  color: #047857;
  line-height: 1.1;
}

.hist-migraine-sub {
  font-size: 10.5px;
  color: #059669;
}

.hist-migraine-badge {
  width: 36px; height: 36px;
  border-radius: 50%;
  background: #059669;
  display: flex; align-items: center; justify-content: center;
  color: #fff;
  font-size: 16px;
  flex-shrink: 0;
}

/* ── View Full Report Button ─────────────────────────── */
.hist-report-btn {
  width: 100%;
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 16px;
  padding: 16px;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  box-shadow: 0 4px 16px rgba(37,99,235,0.28);
  transition: all 0.2s;
}

.hist-report-btn:hover {
  background: #1d4ed8;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(37,99,235,0.38);
}

.hist-report-btn i { font-size: 15px; }

/* ── Bottom Nav (shared) ─────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }

.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

/* ── Interventions Screen ──────────────────────────────── */

.intv-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
  position: relative;
}

/* ── Scrollable ──────────────────────────────────────── */
.intv-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 16px;
}
.intv-scroll::-webkit-scrollbar { display: none; }

/* ── Title & Subtitle ────────────────────────────────── */
.intv-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 4px 0 4px;
}

.intv-subtitle {
  font-size: 12px;
  color: #7a8cad;
  margin-bottom: 14px;
  line-height: 1.4;
}

/* ── High Stress Alert Banner ────────────────────────── */
.intv-alert-banner {
  display: flex;
  align-items: center;
  justify-content: space-between;
  background: linear-gradient(135deg, #fff0f0 0%, #ffe4e4 100%);
  border: 1.5px solid #fecaca;
  border-radius: 18px;
  padding: 14px;
  margin-bottom: 14px;
  box-shadow: 0 2px 10px rgba(239,68,68,0.10);
}

.intv-alert-left {
  display: flex;
  align-items: flex-start;
  gap: 12px;
  flex: 1;
}

.intv-alert-icon {
  width: 38px; height: 38px;
  background: #fee2e2;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #ef4444;
  font-size: 17px;
  flex-shrink: 0;
}

.intv-alert-title {
  font-size: 14px;
  font-weight: 800;
  color: #b91c1c;
  margin-bottom: 4px;
}

.intv-alert-desc {
  font-size: 11px;
  color: #dc2626;
  line-height: 1.45;
}

.intv-alert-figure {
  font-size: 42px;
  color: #fca5a5;
  margin-left: 8px;
  flex-shrink: 0;
  line-height: 1;
}

/* ── Guided Breathing Card ───────────────────────────── */
.intv-breathing-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: linear-gradient(135deg, #e8f3ff 0%, #dff0ff 100%);
  border-radius: 20px;
  padding: 16px 14px;
  margin-bottom: 14px;
  box-shadow: 0 2px 14px rgba(37,99,235,0.10);
}

.intv-breathing-left {
  flex: 1;
  min-width: 0;
}

.intv-breathing-title {
  font-size: 16px;
  font-weight: 800;
  color: #1a2b4b;
  margin-bottom: 5px;
}

.intv-breathing-desc {
  font-size: 11.5px;
  color: #5a6882;
  line-height: 1.45;
  margin-bottom: 9px;
}

.intv-breathing-tags {
  display: flex;
  flex-direction: column;
  gap: 4px;
  margin-bottom: 12px;
}

.intv-tag {
  display: flex;
  align-items: center;
  gap: 6px;
  font-size: 11px;
  color: #5a6882;
  font-weight: 500;
}

.intv-tag i { color: #9aadc9; font-size: 11px; }

.intv-start-btn {
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 12px;
  padding: 9px 14px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  gap: 7px;
  box-shadow: 0 3px 12px rgba(37,99,235,0.30);
  transition: all 0.2s;
  white-space: nowrap;
}

.intv-start-btn:hover {
  background: #1d4ed8;
  transform: translateY(-1px);
}

/* Breathing circle */
.intv-breathe-wrap {
  position: relative;
  width: 110px;
  height: 110px;
  flex-shrink: 0;
}

.intv-breathe-svg {
  width: 110px;
  height: 110px;
}

.intv-breathe-center {
  position: absolute;
  inset: 0;
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: 0;
}

.intv-breathe-phase {
  font-size: 10px;
  color: #7a8cad;
  font-weight: 600;
  text-align: center;
  line-height: 1.2;
}

.intv-breathe-count {
  font-size: 30px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1;
}

.intv-breathe-unit {
  font-size: 10px;
  color: #9aadc9;
}

/* ── 3 Mini Cards ────────────────────────────────────── */
.intv-mini-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 10px;
  margin-bottom: 16px;
}

.intv-mini-card {
  background: #fff;
  border-radius: 16px;
  padding: 12px 10px 10px;
  box-shadow: 0 2px 10px rgba(37,99,235,0.07);
  display: flex;
  flex-direction: column;
  gap: 4px;
}

.intv-mini-icon {
  width: 34px; height: 34px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 15px;
  margin-bottom: 4px;
}

.intv-mini-purple { background: #ede9fe; color: #7c3aed; }
.intv-mini-green  { background: #d1fae5; color: #059669; }
.intv-mini-yellow { background: #fef9c3; color: #ca8a04; }

.intv-mini-name {
  font-size: 11.5px;
  font-weight: 700;
  color: #1a2b4b;
  line-height: 1.2;
}

.intv-mini-desc {
  font-size: 10px;
  color: #7a8cad;
  line-height: 1.35;
  flex: 1;
}

.intv-mini-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  margin-top: 6px;
}

.intv-mini-meta {
  display: flex;
  flex-direction: column;
  gap: 1px;
}

.intv-mini-meta span:first-child {
  font-size: 10.5px;
  font-weight: 700;
  color: #1a2b4b;
}

.intv-mini-tags {
  font-size: 9.5px;
  color: #9aadc9;
}

.intv-mini-play {
  width: 28px; height: 28px;
  border-radius: 50%;
  border: none;
  display: flex; align-items: center; justify-content: center;
  font-size: 10px;
  cursor: pointer;
  flex-shrink: 0;
  transition: transform 0.15s;
}

.intv-mini-play:hover { transform: scale(1.1); }

.intv-play-blue   { background: #2563eb; color: #fff; }
.intv-play-green  { background: #059669; color: #fff; }
.intv-play-yellow { background: #f5f0e0; color: #ca8a04; }

/* ── Section Title ───────────────────────────────────── */
.intv-section-title {
  font-size: 13.5px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 10px;
}

/* ── Recommended Card ────────────────────────────────── */
.intv-recommend-card {
  display: flex;
  align-items: center;
  gap: 10px;
  background: #fff;
  border-radius: 16px;
  padding: 13px 13px;
  margin-bottom: 16px;
  box-shadow: 0 2px 10px rgba(37,99,235,0.07);
}

.intv-recommend-icon {
  width: 40px; height: 40px;
  background: #e0f2fe;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  color: #0284c7;
  font-size: 18px;
  flex-shrink: 0;
}

.intv-recommend-info { flex: 1; min-width: 0; }

.intv-recommend-name {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 2px;
}

.intv-recommend-desc {
  font-size: 10.5px;
  color: #7a8cad;
  line-height: 1.35;
}

.intv-recommend-match {
  text-align: center;
  flex-shrink: 0;
}

.intv-match-label {
  font-size: 9.5px;
  color: #9aadc9;
}

.intv-match-val {
  font-size: 15px;
  font-weight: 800;
  color: #22c55e;
}

.intv-try-btn {
  background: #f0f4ff;
  color: #2563eb;
  border: 1.5px solid #dbeafe;
  border-radius: 10px;
  padding: 7px 12px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  flex-shrink: 0;
  transition: all 0.2s;
}

.intv-try-btn:hover {
  background: #2563eb;
  color: #fff;
  border-color: #2563eb;
}

/* ── Recent Completion ───────────────────────────────── */
.intv-completion-card {
  display: flex;
  align-items: center;
  gap: 10px;
  background: #fff;
  border-radius: 16px;
  padding: 13px 13px;
  margin-bottom: 12px;
  box-shadow: 0 2px 10px rgba(37,99,235,0.07);
}

.intv-completion-icon {
  width: 36px; height: 36px;
  background: #d1fae5;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #059669;
  font-size: 18px;
  flex-shrink: 0;
}

.intv-completion-info { flex: 1; min-width: 0; }

.intv-completion-name {
  font-size: 12.5px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 2px;
}

.intv-completion-time {
  font-size: 10.5px;
  color: #9aadc9;
}

.intv-completion-result {
  text-align: right;
  flex-shrink: 0;
}

.intv-result-label {
  font-size: 10px;
  color: #2563eb;
  font-weight: 600;
}

.intv-result-val {
  font-size: 13px;
  font-weight: 800;
  color: #2563eb;
}

.intv-completion-arrow {
  color: #c5d3e8;
  font-size: 11px;
  flex-shrink: 0;
  margin-left: 4px;
}

/* ── Bottom Nav ─────────────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }

.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

