  color: #0284c7;
  font-size: 18px;
  flex-shrink: 0;
}

.intv-recommend-info { flex: 1; min-width: 0; }

.intv-recommend-name {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 2px;
}

.intv-recommend-desc {
  font-size: 10.5px;
  color: #7a8cad;
  line-height: 1.35;
}

.intv-recommend-match {
  text-align: center;
  flex-shrink: 0;
}

.intv-match-label {
  font-size: 9.5px;
  color: #9aadc9;
}

.intv-match-val {
  font-size: 15px;
  font-weight: 800;
  color: #22c55e;
}

.intv-try-btn {
  background: #f0f4ff;
  color: #2563eb;
  border: 1.5px solid #dbeafe;
  border-radius: 10px;
  padding: 7px 12px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  flex-shrink: 0;
  transition: all 0.2s;
}

.intv-try-btn:hover {
  background: #2563eb;
  color: #fff;
  border-color: #2563eb;
}

/* ── Recent Completion ───────────────────────────────── */
.intv-completion-card {
  display: flex;
  align-items: center;
  gap: 10px;
  background: #fff;
  border-radius: 16px;
  padding: 13px;
  margin-bottom: 12px;
  box-shadow: 0 2px 10px rgba(37,99,235,0.07);
}

.intv-completion-icon {
  width: 36px; height: 36px;
  background: #d1fae5;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #059669;
  font-size: 18px;
  flex-shrink: 0;
