}

.intv-completion-time {
  font-size: 10.5px;
  color: #9aadc9;
}

.intv-completion-result {
  text-align: right;
  flex-shrink: 0;
}

.intv-result-label {
  font-size: 10px;
  color: #2563eb;
  font-weight: 600;
}

.intv-result-val {
  font-size: 13px;
  font-weight: 800;
  color: #2563eb;
}

.intv-completion-arrow {
  color: #c5d3e8;
  font-size: 11px;
  flex-shrink: 0;
  margin-left: 4px;
}

/* ── Bottom Nav ─────────────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }

.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

/* ── Feedback Screen ───────────────────────────────────── */

.fb-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
  position: relative;
}

/* ── Scrollable ──────────────────────────────────────── */
.fb-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 16px;
}
.fb-scroll::-webkit-scrollbar { display: none; }

/* ── Title Row ───────────────────────────────────────── */
.fb-title-row {
  display: flex;
  align-items: center;
  gap: 12px;
  margin: 4px 0 14px;
}

.fb-back-btn {
  width: 34px; height: 34px;
  border-radius: 50%;
  border: 1.5px solid #d0dff0;
  background: #fff;
  color: #1a2b4b;
  font-size: 13px;
  display: flex; align-items: center; justify-content: center;
  text-decoration: none;
  flex-shrink: 0;
  box-shadow: 0 1px 6px rgba(37,99,235,0.07);
}

.fb-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 0;
}

/* ── Cards ───────────────────────────────────────────── */
.fb-card {
  background: #fff;
  border-radius: 18px;
  padding: 16px;
  margin-bottom: 14px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
  transition: opacity 0.3s;
}

/* ── Feel Card ───────────────────────────────────────── */
.fb-feel-title {
  font-size: 15px;
  font-weight: 800;
  color: #1a2b4b;
  margin-bottom: 4px;
}

.fb-feel-sub {
  font-size: 11.5px;
  color: #7a8cad;
  margin-bottom: 14px;
  line-height: 1.4;
}

.fb-feel-row {
  display: grid;
  grid-template-columns: repeat(3, 1fr);
  gap: 8px;
}

.fb-feel-btn {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 7px;
  padding: 12px 6px;
  border-radius: 14px;
  border: 2px solid transparent;
  cursor: pointer;
  font-size: 11px;
  font-weight: 600;
  transition: all 0.2s;
  background: #f8faff;
}

.fb-feel-btn i { font-size: 22px; }

.fb-feel-green i   { color: #22c55e; }
.fb-feel-green span{ color: #16a34a; }

.fb-feel-blue i    { color: #2563eb; }
.fb-feel-blue span { color: #2563eb; }

.fb-feel-red i     { color: #ef4444; }
.fb-feel-red span  { color: #ef4444; }

/* Active states */
.fb-feel-green.fb-feel-active { background: #f0fdf4; border-color: #22c55e; }
.fb-feel-blue.fb-feel-active  { background: #eff6ff; border-color: #2563eb; }
.fb-feel-red.fb-feel-active   { background: #fff1f2; border-color: #ef4444; }

/* ── PSS Questionnaire ───────────────────────────────── */
.fb-pss-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 10px;
}

.fb-pss-title {
  font-size: 14px;
  font-weight: 800;
  color: #1a2b4b;
  margin-bottom: 2px;
}

.fb-pss-sub {
  font-size: 11px;
  color: #7a8cad;
}

.fb-pss-progress-label {
  font-size: 11px;
  font-weight: 700;
  color: #2563eb;
  white-space: nowrap;
  flex-shrink: 0;
}

/* Progress bar */
.fb-progress-bar {
  width: 100%;
  height: 5px;
  background: #e8f0fb;
  border-radius: 3px;
  margin-bottom: 14px;
  overflow: hidden;
}

.fb-progress-fill {
  height: 100%;
  background: #2563eb;
  border-radius: 3px;
  transition: width 0.4s ease;
}

/* Question text */
.fb-q-text {
  font-size: 13px;
  font-weight: 600;
  color: #1a2b4b;
  line-height: 1.55;
  margin-bottom: 14px;
}

/* ── Options ─────────────────────────────────────────── */
.fb-options {
  display: flex;
  flex-direction: column;
  gap: 7px;
  margin-bottom: 14px;
}

.fb-option-row {
  display: flex;
  align-items: center;
  gap: 12px;
  padding: 10px 14px;
  border-radius: 12px;
  border: 1.5px solid #e8f0fb;
  background: #fafcff;
  cursor: pointer;
  transition: all 0.18s;
}

.fb-option-row:hover {
  border-color: #a5c4f8;
  background: #f0f6ff;
}

.fb-option-selected {
  background: #f0fdf4 !important;
  border-color: #22c55e !important;
}

.fb-radio-circle {
  width: 20px; height: 20px;
  border-radius: 50%;
  border: 2px solid #c5d3e8;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
  transition: all 0.18s;
}

.fb-radio-filled {
  background: #22c55e;
  border-color: #22c55e;
}

.fb-option-num {
  font-size: 13px;
  font-weight: 700;
  color: #5a6882;
  min-width: 14px;
}

.fb-option-selected .fb-option-num {
  color: #16a34a;
}

.fb-option-label {
  font-size: 13px;
  color: #1a2b4b;
  font-weight: 500;
}

.fb-option-selected .fb-option-label {
  color: #16a34a;
  font-weight: 700;
}

/* ── Prev / Next nav ─────────────────────────────────── */
.fb-nav-row {
  display: flex;
  justify-content: space-between;
  align-items: center;
  margin-bottom: 12px;
}

.fb-nav-btn {
  display: flex;
  align-items: center;
  gap: 6px;
  background: #f0f4ff;
  color: #2563eb;
  border: 1.5px solid #dbeafe;
  border-radius: 10px;
  padding: 7px 14px;
  font-size: 12px;
  font-weight: 700;
  cursor: pointer;
  transition: all 0.18s;
}

.fb-nav-btn:hover {
  background: #2563eb;
  color: #fff;
  border-color: #2563eb;
}

.fb-nav-next {
  background: #2563eb;
  color: #fff;
  border-color: #2563eb;
}

.fb-nav-next:hover {
  background: #1d4ed8;
}

/* ── Info tip ────────────────────────────────────────── */
.fb-tip {
  display: flex;
  align-items: flex-start;
  gap: 9px;
  background: #eff6ff;
  border-radius: 12px;
  padding: 10px 12px;
}

.fb-tip i {
  color: #2563eb;
  font-size: 14px;
  flex-shrink: 0;
  margin-top: 1px;
}

.fb-tip span {
  font-size: 11px;
  color: #3b5fa0;
  line-height: 1.45;
}

/* ── Submit Button ───────────────────────────────────── */
.fb-submit-btn {
  width: 100%;
  background: #2563eb;
  color: #fff;
  border: none;
  border-radius: 16px;
  padding: 16px;
  font-size: 15px;
  font-weight: 700;
  cursor: pointer;
  display: flex;
  align-items: center;
  justify-content: center;
  gap: 10px;
  box-shadow: 0 4px 16px rgba(37,99,235,0.28);
  transition: all 0.35s ease;
  margin-bottom: 14px;
}

.fb-submit-btn:hover:not(:disabled) {
  background: #1d4ed8;
  transform: translateY(-1px);
  box-shadow: 0 6px 20px rgba(37,99,235,0.38);
}

.fb-submit-btn:disabled { cursor: default; }

.fb-submit-success {
  background: #16a34a !important;
  box-shadow: 0 4px 20px rgba(22,163,74,0.35) !important;
  transform: none !important;
}

/* ── Success Message ─────────────────────────────────── */
.fb-success {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 8px;
  background: #f0fdf4;
  border: 1.5px solid #86efac;
  border-radius: 18px;
  padding: 20px 16px;
  margin-bottom: 14px;
  text-align: center;
  animation: fadeInUp 0.4s ease;
}

@keyframes fadeInUp {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

.fb-success-icon {
  width: 56px; height: 56px;
  background: #22c55e;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #fff;
  font-size: 26px;
  margin-bottom: 4px;
}

.fb-success-title {
  font-size: 16px;
  font-weight: 800;
  color: #16a34a;
}

.fb-success-sub {
  font-size: 12px;
  color: #4ade80;
  line-height: 1.5;
  color: #15803d;
}

/* ── Bottom Nav ─────────────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

