  justify-content: center;
  gap: 10px;
  box-shadow: 0 4px 16px rgba(37,99,235,0.28);
  transition: all 0.35s ease;
  margin-bottom: 14px;
}

.fb-submit-btn:hover:not(:disabled) {
  background: #1d4ed8;
  transform: translateY(-1px);
}

.fb-submit-btn:disabled { cursor: default; }

.fb-submit-success {
  background: #16a34a !important;
  box-shadow: 0 4px 20px rgba(22,163,74,0.35) !important;
}

/* ── Success Message ─────────────────────────────────── */
.fb-success {
  flex-direction: column;
  align-items: center;
  gap: 8px;
  background: #f0fdf4;
  border: 1.5px solid #86efac;
  border-radius: 18px;
  padding: 22px 16px;
  margin-bottom: 14px;
  text-align: center;
  animation: fbFadeUp 0.4s ease;
}

@keyframes fbFadeUp {
  from { opacity: 0; transform: translateY(12px); }
  to   { opacity: 1; transform: translateY(0); }
}

.fb-success-icon {
  width: 58px; height: 58px;
  background: #22c55e;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #fff;
  font-size: 28px;
  margin-bottom: 6px;
}

.fb-success-title {
  font-size: 17px;
  font-weight: 800;
  color: #16a34a;
}

.fb-success-sub {
  font-size: 12px;
  color: #15803d;
  line-height: 1.5;
}

/* ── Bottom Nav ─────────────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

/* ── Insights Screen ───────────────────────────────────── */

.ins-screen {
  width: 100%;
  height: 100%;
  display: flex;
  flex-direction: column;
  background: linear-gradient(180deg, #deeeff 0%, #f0f6ff 18%, #f5f8ff 100%);
  overflow: hidden;
  position: relative;
}

/* ── Scrollable ──────────────────────────────────────── */
.ins-scroll {
  flex: 1;
  overflow-y: auto;
  overflow-x: hidden;
  scrollbar-width: none;
  -ms-overflow-style: none;
  padding: 0 16px;
}
.ins-scroll::-webkit-scrollbar { display: none; }

/* ── Title ───────────────────────────────────────────── */
.ins-title {
  font-size: 22px;
  font-weight: 800;
  color: #1a2b4b;
  margin: 4px 0 14px;
}

/* ── Card base ───────────────────────────────────────── */
.ins-card {
  background: #fff;
  border-radius: 18px;
  padding: 14px;
  box-shadow: 0 2px 12px rgba(37,99,235,0.07);
}

/* ── Top 2-col row ───────────────────────────────────── */
.ins-top-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-bottom: 12px;
}

/* ── Sleep Quality Card ──────────────────────────────── */
.ins-sleep-card {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

.ins-card-header {
  display: flex;
  align-items: center;
  gap: 7px;
  margin-bottom: 8px;
}

.ins-sleep-icon {
  position: relative;
  width: 28px; height: 28px;
  background: #e0f2fe;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #0284c7;
  font-size: 14px;
  flex-shrink: 0;
}

.ins-star-sm {
  position: absolute;
  top: -3px; right: -3px;
  font-size: 8px;
  color: #f59e0b;
}

.ins-card-title {
  font-size: 12.5px;
  font-weight: 800;
  color: #1a2b4b;
}

.ins-sleep-dur-label {
  font-size: 9.5px;
  color: #9aadc9;
  margin-bottom: 2px;
}

.ins-sleep-dur {
  font-size: 20px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1.1;
  margin-bottom: 8px;
}

.ins-sleep-dur span { font-size: 16px; }

.ins-sleep-score-label {
  font-size: 9.5px;
  color: #9aadc9;
  margin-bottom: 4px;
}

.ins-sleep-gauge-wrap {
  position: relative;
  width: 72px; height: 72px;
  margin-bottom: 4px;
}

.ins-sleep-gauge { width: 72px; height: 72px; }

.ins-sleep-gauge-center {
  position: absolute;
  inset: 0;
  display: flex; flex-direction: column; align-items: center; justify-content: center;
}

.ins-sleep-score {
  font-size: 20px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1;
}

.ins-sleep-unit {
  font-size: 9px;
  color: #9aadc9;
}

.ins-sleep-good {
  font-size: 12px;
  font-weight: 700;
  color: #22c55e;
}

/* ── Migraine Risk Card ──────────────────────────────── */
.ins-migraine-card {
  display: flex;
  flex-direction: column;
  align-items: flex-start;
}

.ins-migraine-icon {
  width: 28px; height: 28px;
  background: #f0fdf4;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  color: #16a34a;
  font-size: 14px;
  flex-shrink: 0;
}

.ins-risk-level-label {
  font-size: 9.5px;
  color: #9aadc9;
  margin-bottom: 3px;
}

.ins-risk-level-val {
  font-size: 16px;
  font-weight: 800;
  color: #f59e0b;
  line-height: 1.1;
  margin-bottom: 10px;
}

/* Risk slider bar */
.ins-risk-slider-wrap {
  width: 100%;
  margin-bottom: 8px;
}

.ins-risk-slider-bar {
  width: 100%;
  height: 8px;
  border-radius: 6px;
  background: linear-gradient(90deg, #22c55e 0%, #f59e0b 50%, #ef4444 100%);
  position: relative;
}

.ins-risk-thumb {
  position: absolute;
  top: 50%;
  transform: translate(-50%, -50%);
  width: 14px; height: 14px;
  background: #fff;
  border: 2.5px solid #f59e0b;
  border-radius: 50%;
  box-shadow: 0 1px 4px rgba(0,0,0,0.2);
}

.ins-risk-score-label {
  font-size: 9.5px;
  color: #9aadc9;
  margin-bottom: 2px;
}

.ins-risk-score-val {
  font-size: 18px;
  font-weight: 800;
  color: #1a2b4b;
  line-height: 1;
}

.ins-risk-score-val span {
  font-size: 12px;
  font-weight: 500;
  color: #9aadc9;
}

/* ── Chart Card ──────────────────────────────────────── */
.ins-chart-card {
  margin-bottom: 12px;
}

.ins-chart-header {
  display: flex;
  justify-content: space-between;
  align-items: flex-start;
  margin-bottom: 10px;
  flex-wrap: wrap;
  gap: 6px;
}

.ins-chart-title {
  font-size: 13.5px;
  font-weight: 800;
  color: #1a2b4b;
}

.ins-chart-sub {
  font-size: 10px;
  color: #9aadc9;
}

.ins-chart-legend {
  display: flex;
  align-items: center;
  gap: 4px;
  flex-wrap: wrap;
}

.ins-legend-dot {
  width: 10px; height: 3px;
  border-radius: 2px;
  display: inline-block;
}

.ins-legend-label {
  font-size: 9.5px;
  color: #7a8cad;
  font-weight: 500;
}

.ins-chart-wrap {
  width: 100%;
  overflow: hidden;
}

/* ── Bottom 2-col row ────────────────────────────────── */
.ins-bottom-row {
  display: grid;
  grid-template-columns: 1fr 1fr;
  gap: 10px;
  margin-bottom: 12px;
}

/* ── Risk Factors Card ───────────────────────────────── */
.ins-risk-card, .ins-rec-card {
  display: flex;
  flex-direction: column;
  gap: 0;
}

.ins-section-title {
  font-size: 11.5px;
  font-weight: 800;
  color: #1a2b4b;
  display: flex;
  align-items: center;
  gap: 5px;
  margin-bottom: 10px;
}

.ins-risk-list, .ins-rec-list {
  display: flex;
  flex-direction: column;
  gap: 8px;
}

.ins-risk-item {
  display: flex;
  align-items: flex-start;
  gap: 7px;
}

.ins-risk-icon {
  width: 26px; height: 26px;
  border-radius: 50%;
  display: flex; align-items: center; justify-content: center;
  font-size: 11px;
  flex-shrink: 0;
}

.ins-risk-info { flex: 1; min-width: 0; }

.ins-risk-name {
  font-size: 10.5px;
  font-weight: 700;
  color: #1a2b4b;
  line-height: 1.2;
}

.ins-risk-sub {
  font-size: 9.5px;
  color: #9aadc9;
  line-height: 1.2;
}

.ins-badge {
  font-size: 9px;
  font-weight: 700;
  border-radius: 6px;
  padding: 2px 6px;
  flex-shrink: 0;
  white-space: nowrap;
}

.ins-badge-red    { background: #fee2e2; color: #ef4444; }
.ins-badge-yellow { background: #fef9c3; color: #ca8a04; }

/* ── Recommendations Card ────────────────────────────── */
.ins-rec-item {
  display: flex;
  align-items: flex-start;
  gap: 8px;
}

.ins-rec-icon {
  width: 26px; height: 26px;
  border-radius: 8px;
  display: flex; align-items: center; justify-content: center;
  flex-shrink: 0;
}

.ins-rec-text {
  font-size: 10.5px;
  color: #1a2b4b;
  line-height: 1.4;
  font-weight: 500;
}

/* ── Warning Alerts Card ─────────────────────────────── */
.ins-alert-card {
  display: flex;
  align-items: center;
  gap: 12px;
  background: #fff;
  border-radius: 16px;
  padding: 14px;
  margin-bottom: 12px;
  box-shadow: 0 2px 10px rgba(37,99,235,0.07);
  text-decoration: none;
  border: 1.5px solid #e8f0fb;
  transition: border-color 0.2s, box-shadow 0.2s;
}

.ins-alert-card:hover {
  border-color: #2563eb;
  box-shadow: 0 4px 16px rgba(37,99,235,0.13);
}

.ins-alert-icon-wrap {
  width: 40px; height: 40px;
  background: #eff6ff;
  border-radius: 12px;
  display: flex; align-items: center; justify-content: center;
  color: #2563eb;
  font-size: 18px;
  flex-shrink: 0;
}

.ins-alert-info { flex: 1; }

.ins-alert-title {
  font-size: 13px;
  font-weight: 700;
  color: #1a2b4b;
  margin-bottom: 2px;
}

.ins-alert-sub {
  font-size: 11px;
  color: #9aadc9;
}

.ins-alert-arrow {
  color: #c5d3e8;
  font-size: 12px;
  flex-shrink: 0;
}

/* ── Bottom Nav ─────────────────────────────────────── */
.dp-bottom-nav {
  display: flex;
  justify-content: space-around;
  align-items: center;
  background: #fff;
  border-top: 1px solid #e8f0fb;
  padding: 8px 0 10px;
  flex-shrink: 0;
}

.dp-bottom-nav .nav-item {
  display: flex;
  flex-direction: column;
  align-items: center;
  gap: 3px;
  text-decoration: none;
  color: #9aadc9;
  font-size: 10px;
  font-weight: 500;
  transition: color 0.2s;
}

.dp-bottom-nav .nav-item i { font-size: 18px; }
.dp-bottom-nav .nav-item.nav-active { color: #2563eb; }

